mapper.select:
SELECT *
FROM sys_operation_log
WHERE deleted = 0

    AND account_id = #{accountId}


    AND operator_name LIKE CONCAT('%', #{operatorName}, '%')


    AND operator_ip LIKE CONCAT(#{operatorIp}, '%')


    AND log_level = #{logLevel}


    AND module_name LIKE CONCAT('%', #{moduleName}, '%')


    AND operation_item LIKE CONCAT('%', #{operationItem}, '%')


    AND (request_params LIKE CONCAT('%', #{operationDetail}, '%')
        OR change_records LIKE CONCAT('%', #{operationDetail}, '%'))


    AND execute_result = #{executeResult}


    AND operate_time >= #{startTime}


    AND operate_time <= #{endTime}



        ORDER BY operate_time ASC


        ORDER BY operate_time DESC
